def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.nan, dtype=float)
    item_exp = np.exp(item)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        complexity_factor = 1.0
        decay_factor = 1.0
        interaction_score = 0.0
        if cap < item:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        for a in range(1, 15):
            for b in range(1, 8):
                if (a * b) % 4 == 0:
                    factor1 = np.tanh(ratio * a) * np.log1p(b)
                else:
                    factor1 = np.cos(ratio * b / (a + 1)) + np.sin(a / (b + 1))
                if cap % (a + b) == 0:
                    factor2 = np.sqrt(abs(cap - item * (a + b))) * 0.75
                else:
                    factor2 = np.exp(-abs(cap - item * (a + b))/ (a*b+1))
                base_score += factor1 * factor2 * np.power(1.1, (a % 3) - 1)
                if (cap + a * b) % 9 == 0:
                    base_score *= 1.03
                elif (cap * b - a) % 11 == 0:
                    base_score *= 0.97
                if a == 7:
                    for c in range(1, 4):
                        val = cap - item * (c ** 3)
                        if val > 0:
                            interaction_score += np.log1p(val) / (c + 2) * (1 + 0.1 * c)
                        else:
                            interaction_score -= np.abs(val) ** 1.1 / (c + 3)
            if ratio > 0.75 and a % 2 == 1:
                complexity_factor *= 1.12 + 0.015 * a
            elif ratio < 0.15 and a % 4 == 0:
                complexity_factor *= 0.88 - 0.012 * a
            if (cap + a) % 5 == 0:
                decay_factor *= 0.95
            else:
                decay_factor *= 1.03
            if a % 5 == 2:
                base_score += np.sin(a * ratio) * 0.7
        total_score = (base_score + interaction_score * 0.85) * complexity_factor * decay_factor
        if total_score < 0:
            priority = -total_score * (np.log1p(cap) + np.sqrt(item))
        else:
            if cap > item * 3.5:
                priority = -total_score / (np.sqrt(cap) + 2) * (1 + ratio * 1.1)
            else:
                priority = -total_score / (cap + 4) * np.exp(-ratio ** 2 / 1.5)
        if ratio > 0.9:
            priority *= 1.2 + 0.05 * (np.tanh(cap / item))
        elif ratio < 0.1:
            priority *= 0.7 - 0.03 * (np.log1p(item))
        if cap % 3 == 0:
            priority *= 0.96
        else:
            priority *= 1.04
        priorities[i] = priority
    return priorities
